class TweetCounts {
public:
    unordered_map<string, vector<int>> tweetTimes;

    TweetCounts() {

    }

    void recordTweet(string tweetName, int time) {
        tweetTimes[tweetName].push_back(time);
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        int chunkSize = 0;
        if (freq == "minute") chunkSize = 60;
        else if (freq == "hour") chunkSize = 3600;
        else chunkSize = 86400;

        vector<int> counts;
        int start = startTime;
        while (start <= endTime) {
            int end = min(start + chunkSize - 1, endTime);
            int count = 0;
            for (int time : tweetTimes[tweetName]) {
                if (time >= start && time <= end) count++;
            }
            counts.push_back(count);
            start += chunkSize;
        }
        return counts;
    }
};

